	"\u5df2\u8f09\u5165\u904e [%1]\uff0c\u76f4\u63a5\u8a2d\u5b9a\u4f7f\u7528\u8005\u81ea\u8a02\u8cc7\u6e90\u3002": "[%1]\uc774(\uac00) \ub85c\ub4dc\ub418\uc5c8\uc2b5\ub2c8\ub2e4. \uc774\uc81c \uc0ac\uc6a9\uc790 \ub3c4\uba54\uc778 \ub9ac\uc18c\uc2a4\ub97c \uc124\uc815\ud569\ub2c8\ub2e4.",
	"\u5f37\u5236\u518d\u6b21\u8f09\u5165/\u4f7f\u7528 [%2] (%1) \u9818\u57df/\u8a9e\u7cfb\u3002": "\ub3c4\uba54\uc778/\ub85c\ucf00\uc77c [%2] (%1)\uc744 \uac15\uc81c\ub85c \ub85c\ub4dc/\uc0ac\uc6a9\ud569\ub2c8\ub2e4.",
	"\u8f09\u5165/\u4f7f\u7528 [%2] (%1) \u9818\u57df/\u8a9e\u7cfb\u3002": "\ub3c4\uba54\uc778/\ub85c\ucf00\uc77c [%2] (%1)\uc744 \ub85c\ub4dc/\uc0ac\uc6a9\ud569\ub2c8\ub2e4.",
	"\u7121\u6cd5\u5224\u5225 domain\uff0c\u537b\u8a2d\u5b9a\u6709 callback\u3002": "\ub3c4\uba54\uc778\uc744 \uad6c\ubd84\ud560 \uc218 \uc5c6\uc9c0\ub9cc \ucf5c\ubc31\uc744 \uc124\uc815\ud588\uc2b5\ub2c8\ub2e4.",
	"Illegal domain alias list: [%1]": "\uc798\ubabb\ub41c \ub3c4\uba54\uc778 \ubcc4\uce6d \ubaa9\ub85d: [%1]",
	"Adding domain alias [%1] \u2192 [%2]...": "\ub3c4\uba54\uc778 \ubcc4\uce6d [%1] \u2192 [%2] \ucd94\uac00 \uc911...",
	"Testing domain alias [%1]...": "\ub3c4\uba54\uc778 \ubcc4\uce6d [%1] \ud14c\uc2a4\ud2b8 \uc911...",
