	"Language / domain [%1] loaded.": "\uc5b8\uc5b4/\ub3c4\uba54\uc778 [%1]\uc774 \ub85c\ub4dc\ub418\uc5c8\uc2b5\ub2c8\ub2e4.",
	"Cannot find menu node: [%1]": "\uba54\ub274 \ub178\ub4dc\ub97c \ucc3e\uc744 \uc218 \uc5c6\uc74c: [%1]",
	"Language": "\uc5b8\uc5b4",
	"\u8f49\u63db\u6578\u5b57\uff1a[%1]\u6210 %2 \u683c\u5f0f\u3002": "\uc22b\uc790 \ubcc0\ud658: [%1]\uc744 %2 \ud615\uc2dd\uc73c\ub85c \ubcc0\ud658\ud569\ub2c8\ub2e4.",
	"\u7121\u6cd5\u8f49\u63db\u6578\u5b57 [%1]\uff01": "\uc22b\uc790 [%1]\uc744 \ubcc0\ud658\ud560 \uc218 \uc5c6\uc2b5\ub2c8\ub2e4!",
	"\u8f38\u5165\u4e86\u975e\u5b57\u4e32\u4e4b\u53c3\u6578\uff1a[%1]": "\ubb38\uc790\uc5f4\uc774 \uc544\ub2cc \ub9e4\uac1c\ubcc0\uc218\ub97c \uc785\ub825\ud588\uc2b5\ub2c8\ub2e4: [%1]",
	"\u8a2d\u5b9a %1 \u6210\u975e\u5b57\u4e32\u4e4b\u53c3\u6578\uff1a%2": "%1\uc744(\ub97c) \ubb38\uc790\uc5f4\uc774 \uc544\ub2cc \uac12\uc73c\ub85c \uc124\uc815: %2",
	"\u5171%1\u500b\u53c3\u6578\uff1a": "\ucd1d %1\uac1c \ub9e4\uac1c\ubcc0\uc218:",
