	"Error: connect ETIMEDOUT %1": "\uc11c\ubc84 \uc5f0\uacb0 \uc2dc\uac04\uc774 \ucd08\uacfc\ub418\uc5c8\uc2b5\ub2c8\ub2e4: %1",
