	"Error: Timeout %1": "\uc5f0\uacb0 \uc2dc\uac04\uc774 %1\uc744(\ub97c) \ucd08\uacfc\ud588\uc2b5\ub2c8\ub2e4",
	"Error: read ECONNRESET": "\ud53c\uc5b4\uac00 \uc5f0\uacb0\uc744 \uc7ac\uc124\uc815\ud588\uc2b5\ub2c8\ub2e4",
	"Error: socket hang up": "\uc18c\ucf13\uc774 \ub04a\uc5b4\uc84c\uc2b5\ub2c8\ub2e4",
	"Error: unexpected end of file": "\ubd88\uc644\uc804\ud55c \ub370\uc774\ud130\ub97c \uc218\uc2e0\ud588\uc2b5\ub2c8\ub2e4",
