	"\u81ea\u7db2\u8def\u53d6\u5f97 URL\uff1a%1\uff0c%2{{PLURAL:%2|\u4f4d\u5143\u7d44}}\u3002": "\ub124\ud2b8\uc6cc\ud06c\uc5d0\uc11c URL\uc744 \uac00\uc838\uc654\uc2b5\ub2c8\ub2e4: %1, %2 {{PLURAL:%2|\ubc14\uc774\ud2b8}}.",
	"Invalid cookie?": "\uc720\ud6a8\ud558\uc9c0 \uc54a\uc740 \ucfe0\ud0a4?",
	"cookie \u540d\u7a31\u91cd\u8907\uff01\u4ee5\u5f8c\u4f86/\u65b0\u51fa\u73fe\u8005\u70ba\u6e96\u3002": "\uc911\ubcf5\ub41c \ucfe0\ud0a4 \uc774\ub984\uc785\ub2c8\ub2e4! \ub098\uc911/\uc0c8 \ud56d\ubaa9\uc774 \uc6b0\uc120\ud569\ub2c8\ub2e4.",
	"Waiting %1/%2 {{PLURAL:%1|connection|connections}}: %3": "%1/%2 {{PLURAL:%1|\uc5f0\uacb0}} \ub300\uae30 \uc911: %3",
