	"Using HTTP proxy to get URL: %1": "HTTP \ud504\ub85d\uc2dc\ub97c \uc0ac\uc6a9\ud558\uc5ec URL \uac00\uc838\uc624\uae30: %1",
	"\u4f7f\u7528\u65b0 agent\u3002": "\uc0c8 \uc5d0\uc774\uc804\ud2b8\ub97c \uc0ac\uc6a9\ud569\ub2c8\ub2e4.",
	"\u4f7f\u7528\u81ea\u5b9a\u7fa9 agent\u3002": "\uc0ac\uc6a9\uc790 \uc9c0\uc815 \uc5d0\uc774\uc804\ud2b8\ub97c \uc0ac\uc6a9\ud569\ub2c8\ub2e4.",
	"\u81ea\u5b9a\u7fa9 agent \u8207 URL \u4e4b\u5354\u5b9a\u4e0d\u540c\uff0c\u5c07\u5617\u8a66\u63a1\u7528\u7b26\u5408\u7684\u5354\u5b9a\uff1a%1": "\uc0ac\uc6a9\uc790 \uc9c0\uc815 \uc5d0\uc774\uc804\ud2b8\uac00 URL\uacfc \ub2e4\ub974\ubbc0\ub85c \uc77c\uce58\ud558\ub294 \ud504\ub85c\ud1a0\ucf5c \ucc44\ud0dd\uc744 \uc2dc\ub3c4\ud569\ub2c8\ub2e4: %1",
	"\u63a1\u7528\u6cdb\u7528\u7684 agent\u3002": "\uc77c\ubc18 \uc5d0\uc774\uc804\ud2b8\ub97c \uc0ac\uc6a9\ud569\ub2c8\ub2e4.",
