	"Please set tls.DEFAULT_MIN_VERSION = \"TLSv1\" first!": "\uba3c\uc800 tls.DEFAULT_MIN_VERSION = \"TLSv1\"\uc744 \uc124\uc815\ud558\uc138\uc694!",
	"%1 Redirecting to [%2] \u2190 [%3]": "%1 [%2] \u2190 [%3](\uc73c)\ub85c \ub9ac\ub514\ub809\uc158 \uc911",
