	"\u7b49\u5f85\u63a5\u6536\u5f9e\u7db2\u5740 [%1] \u50b3\u8f38\u56de\u7684\u8cc7\u6599\u2026\u2026": "URL [%1]\uc5d0\uc11c \ub2e4\uc2dc \uc804\uc1a1\ub41c \ub370\uc774\ud130\ub97c \uc218\uc2e0\ud558\ub294 \uc911...",
