	"\u7121 node.js \u4e4b `fs` \u5957\u4ef6\uff0c\u56e0\u6b64\u4e0d\u5177\u5099 node \u4e4b\u6a94\u6848\u64cd\u4f5c\u529f\u80fd\u3002": "node.js\uc6a9 `fs` \ud328\ud0a4\uc9c0\uac00 \uc5c6\uc73c\ubbc0\ub85c \ub178\ub4dc\uc5d0\uc11c \ud30c\uc77c \uc791\uc5c5 \ud568\uc218\ub97c \uc0ac\uc6a9\ud560 \uc218 \uc5c6\uc2b5\ub2c8\ub2e4",
	"\u81ea URL \u53d6\u5f97\u6a94\u540d\uff1a%1": "URL\uc5d0\uc11c \ud30c\uc77c \uc774\ub984 \uac00\uc838\uc624\uae30: %1",
	"No file name specified.": "\ud30c\uc77c \uc774\ub984\uc774 \uc9c0\uc815\ub418\uc9c0 \uc54a\uc558\uc2b5\ub2c8\ub2e4.",
