	"\u5617\u8a66\u91cd\u65b0\u53d6\u5f97\u4ee4\u724c\u3002": "\ud1a0\ud070\uc744 \ub2e4\uc2dc \uac00\uc838\uc624\ub824\uace0 \uc2dc\ub3c4\ud569\ub2c8\ub2e4.",
	"\u7db2\u5740\u7121\u6548\uff1a%1": "\uc798\ubabb\ub41c URL: %1",
