	"Waiting %1...": "%1 \ub300\uae30 \uc911...",
	"\u7121\u9801\u9762\u91cd\u5b9a\u5411\u81f3\u672c\u9801": "\uc774 \ud398\uc774\uc9c0\ub85c \ub9ac\ub514\ub809\uc158\ub418\ub294 \ud398\uc774\uc9c0\uac00 \uc5c6\uc2b5\ub2c8\ub2e4",
	"\u5171\u6709%1\u500b{{PLURAL:%1|\u9801\u9762}}\u91cd\u5b9a\u5411\u81f3\u672c\u9801": "\ucd1d %1\uac1c {{PLURAL:%1|\ud398\uc774\uc9c0}}\uac00 \uc774 \ud398\uc774\uc9c0\ub85c \ub9ac\ub514\ub809\uc158\ub429\ub2c8\ub2e4",
	"no change": "\ubcc0\uacbd \uc5c6\uc74c",
