	"First, it takes %1 to get %2 {{PLURAL:%2|page|pages}}.": "\uba3c\uc800 %2\uac1c {{PLURAL:%2|\ud398\uc774\uc9c0}}\ub97c \uac00\uc838\uc624\ub294 \ub370 %1\uc774(\uac00) \uac78\ub9bd\ub2c8\ub2e4.",
	"Processed %1 {{PLURAL:%1|page|pages}}.": "%1\uac1c {{PLURAL:%1|\ud398\uc774\uc9c0}} \ucc98\ub9ac\ub428.",
