	"Maintenance template list": "\uc720\uc9c0\ubcf4\uc218 \ud2c0 \ubaa9\ub85d",
	"Maintenance template list to be excluded": "\uc81c\uc678\ud560 \uc720\uc9c0\ubcf4\uc218 \ud2c0 \ubaa9\ub85d",
	"Categories added to the report": "\ubcf4\uace0\uc11c\uc5d0 \ucd94\uac00\ub41c \ubd84\ub958",
