	"Create {{%2}} with %1 maintenance {{PLURAL:%1|template|templates}}": "%1\uac1c\uc758 \uc720\uc9c0\ubcf4\uc218 {{PLURAL:%1|\ud2c0}}\ub85c {{%2}} \uc0dd\uc131",
	"Remove {{%2}} for only %1 maintenance {{PLURAL:%1|template|templates}}": "%1\uac1c\uc758 \uc720\uc9c0\ubcf4\uc218 {{PLURAL:%1|\ud2c0}}\ub85c {{%2}} \uc81c\uac70",
	"Total %1 {{PLURAL:%1|article|articles}}.": "\ucd1d %1\uac1c {{PLURAL:%1|\ubb38\uc11c}}.",
	"number-of-templates": "#",
	"Articles containing maintenance templates": "\uc720\uc9c0\ubcf4\uc218 \ud2c0\uc774 \ud3ec\ud568\ub41c \ubb38\uc11c",
	"The articles containing too many maintenance templates are listed below:": "\uc720\uc9c0\ubcf4\uc218 \ud2c0\uc774 \ub108\ubb34 \ub9ce\uc774 \ud3ec\ud568\ub41c \ubb38\uc11c\ub294 \uc544\ub798\uc5d0 \ub098\uc5f4\ub418\uc5b4 \uc788\uc2b5\ub2c8\ub2e4:",
	"The report will be updated weekly by the robot.": "\ubcf4\uace0\uc11c\ub294 \ub85c\ubd07\uc5d0 \uc758\ud574 \ub9e4\uc8fc \uc5c5\ub370\uc774\ud2b8\ub429\ub2c8\ub2e4.",
	"You can change the configuration from %1.": "%1\uc5d0\uc11c \uc124\uc815\uc744 \ubcc0\uacbd\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.",
