	"\u958b\u59cb\u4e0b\u8f09\u5b89\u88dd\u5305\u3002\u82e5\u9084\u6c92\u4e0b\u8f09\u5b8c\u5c31\u96e2\u958b\u7a0b\u5f0f\u3001\u51fa\u932f\uff0c\u4e0b\u6b21\u6703\u5f9e\u982d\u4e0b\u8f09\u3002\u60a8\u53ef\u5347\u9ad8\u8a0a\u606f\u6b04\u7684\u5075\u932f\u7b49\u7d1a\uff0c\u4ee5\u5f97\u77e5\u4e0b\u8f09\u9032\u5ea6\u3002": "\uc124\uce58 \ud328\ud0a4\uc9c0 \ub2e4\uc6b4\ub85c\ub4dc\ub97c \uc2dc\uc791\ud588\uc2b5\ub2c8\ub2e4. \ud504\ub85c\uadf8\ub7a8\uc744 \ub2e4\uc6b4\ub85c\ub4dc\ud558\uc9c0 \uc54a\uc558\ub2e4\uba74 \ud504\ub85c\uadf8\ub7a8\uc744 \uc885\ub8cc\ud558\uace0 \ucc98\uc74c\ubd80\ud130 \ub2e4\uc6b4\ub85c\ub4dc\ud558\uc138\uc694. \ub2e4\uc6b4\ub85c\ub4dc \uc9c4\ud589 \uc0c1\ud669\uc744 \uc54c\ub824\uba74 \uba54\uc2dc\uc9c0 \ud45c\uc2dc\uc904\uc758 \ub514\ubc84\uadf8 \uc218\uc900\uc744 \ub192\uc77c \uc218 \uc788\uc2b5\ub2c8\ub2e4.",
	"\u6c92\u6709\u65b0\u5b89\u88dd\u5305\u3002\u7576\u524d\u7248\u672c\uff1a%1": "\ub9b4\ub9ac\uc2a4 \uc5c5\ub370\uc774\ud2b8\ub97c \uc0ac\uc6a9\ud560 \uc218 \uc5c6\uc2b5\ub2c8\ub2e4. \ud604\uc7ac \ubc84\uc804: %1",
	"\u5b89\u88dd\u5305\u66f4\u65b0\u51fa\u932f\uff1a%1": "\uc790\ub3d9 \uc5c5\ub370\uc774\ud2b8 \uc624\ub958: %1",
	"\u5b89\u88dd\u5305\u5df2\u4e0b\u8f09 %1\uff0c\u4e0b\u8f09\u901f\u5ea6 %2 {{PLURAL:%2|byte|bytes}}/s\u3002": "\ub2e4\uc6b4\ub85c\ub4dc \uc18d\ub3c4: %2 {{PLURAL:%2|\ubc14\uc774\ud2b8}}/\ucd08 - \ub2e4\uc6b4\ub85c\ub4dc\ub428 %1",
	"\u5b89\u88dd\u5305\u5df2\u4e0b\u8f09 %1\uff0c\u9810\u4f30\u9084\u9700 %2 {{PLURAL:%2|\u5206\u9418}}\u4e0b\u8f09\u5b8c\u7562\u3002": "\uc124\uce58 \ud328\ud0a4\uc9c0\uac00 %1 \ub2e4\uc6b4\ub85c\ub4dc\ub418\uc5c8\uc73c\uba70 \uc644\ub8cc\uae4c\uc9c0 %2{{PLURAL:%2|\ubd84}}\uc774 \uac78\ub9b4 \uac83\uc73c\ub85c \uc608\uc0c1\ub429\ub2c8\ub2e4.",
	"\u65b0\u7248\u5b89\u88dd\u5305\u4e0b\u8f09\u5b8c\u6210\uff1a%1": "\uc0c8 \ub9b4\ub9ac\uc2a4\uac00 \ub2e4\uc6b4\ub85c\ub4dc\ub418\uc5c8\uc2b5\ub2c8\ub2e4: %1",
	"\u91cd\u65b0\u555f\u52d5\u7a0b\u5f0f\u5373\u53ef\u66f4\u65b0\u3002": "\uc5c5\ub370\uc774\ud2b8\ub97c \uc801\uc6a9\ud558\ub824\uba74 \uc560\ud50c\ub9ac\ucf00\uc774\uc158\uc744 \ub2e4\uc2dc \uc2dc\uc791\ud558\uc138\uc694.",
	"\u5b89\u88dd\u5305\u66f4\u65b0\u5931\u6557\uff1a%1": "\uc560\ud50c\ub9ac\ucf00\uc774\uc158 \uc5c5\ub370\uc774\ud2b8 \uc911 \ubb38\uc81c\uac00 \ubc1c\uc0dd\ud588\uc2b5\ub2c8\ub2e4: %1",
