	"download_options.proxy": "\ud504\ub85d\uc2dc \uc11c\ubc84. \ud3ec\ub9f7: \"\uc0ac\uc6a9\uc790\uc774\ub984:\ube44\ubc00\ubc88\ud638@\ud638\uc2a4\ud2b8\uc774\ub984:\ud3ec\ud2b8\"",
	"download_options.rearrange_list_file": "\ubaa9\ub85d \ud30c\uc77c\uc744 \uc7ac\uc815\ub82c\ud569\ub2c8\ub2e4.",
	"download_options.recheck": "\ubaa8\ub4e0 \uc791\ud488\uc758 \ubaa8\ub4e0 \uc7a5\uacfc \uc774\ubbf8\uc9c0\ub97c \uac10\uc9c0\ud569\ub2c8\ub2e4. \ud558\uc9c0\ub9cc \uc644\ub8cc\ub41c \uc774\ubbf8\uc9c0\ub294 \ub2e4\uc2dc \ub2e4\uc6b4\ub85c\ub4dc\ud558\uc9c0 \uc54a\uc2b5\ub2c8\ub2e4. 'multi_parts_changed'\uac00 \uc124\uc815\ub41c \uacbd\uc6b0 \uc5ec\ub7ec \ubd80\ubd84\uc774 \uc788\uc744 \ub54c\ub9cc \ub2e4\uc2dc \ud655\uc778\ud569\ub2c8\ub2e4.",
	"download_options.regenerate": "\uc7a5 \uc218\uc5d0 \ubcc0\ud654\uac00 \uc5c6\uc5b4\ub3c4 \uce90\uc2dc\ub97c \uc0ac\uc6a9\ud558\uc5ec \ub370\uc774\ud130\ub97c \uc7ac\uad6c\uc131\ud569\ub2c8\ub2e4. (\uc608: \uc18c\uc124\uc744 \ub2e4\uc6b4\ub85c\ub4dc\ud560 \ub54c \uc6f9\ubb38\uc11c \ub370\uc774\ud130\ub97c \ub2e4\uc2dc \uac00\uc838\uc624\uc9c0 \uc54a\uace0 \uc804\uc790\ucc45 \ud30c\uc77c\ub9cc \ub2e4\uc2dc \ube4c\ub4dc\ud569\ub2c8\ub2e4.)",
	"download_options.reget_chapter": "\uac10\uc9c0\ub41c \uac01 \uc7a5\uc758 \ub0b4\uc6a9\uc744 \ub2e4\uc2dc \uac00\uc838\uc635\ub2c8\ub2e4.",
