	"download_options.remove_images_after_archive": "\uc774\ubbf8\uc9c0 \ud30c\uc77c\uc744 \uc555\ucd95\ud55c \ud6c4 \uc6d0\ubcf8 \uc774\ubbf8\uc9c0 \ud30c\uc77c\uc744 \uc0ad\uc81c\ud569\ub2c8\ub2e4.",
	"download_options.save_preference": "\ud658\uacbd\uc124\uc815\uc744 \uc800\uc7a5\ud569\ub2c8\ub2e4.",
	"download_options.search_again": "\uc791\ud488 \uc81c\ubaa9\uc744 \ub2e4\uc2dc \uac80\uc0c9\ud569\ub2c8\ub2e4. \uae30\ubcf8\uac12: \uce90\uc2dc\ub97c \uc0ac\uc6a9\ud558\uba70 \ub2e4\uc2dc \uac80\uc0c9\ud558\uc9c0 \uc54a\uc2b5\ub2c8\ub2e4.",
