	"download_options.skip_error": "\uc774\ubbf8\uc9c0 \uc624\ub958\ub97c \ubb34\uc2dc/\uac74\ub108\ub701\ub2c8\ub2e4. 404 \uc774\ubbf8\uc9c0\uac00 \uc874\uc7ac\ud558\uc9c0 \uc54a\uac70\ub098 \ud30c\uc77c\uc774 \ub108\ubb34 \uc791\uac70\ub098 \uc774\ubbf8\uc9c0\uac00 \uc544\ub2cc \uac83\uc73c\ub85c \uac10\uc9c0\ub418\uc5b4\ub3c4(EOI\uac00 \uc5c6\ub294 \uacbd\uc6b0) \ud30c\uc77c\uc744 \uac15\uc81c\ub85c \uc800\uc7a5\ud569\ub2c8\ub2e4.",
	"download_options.start_chapter": "\ub2e4\uc6b4\ub85c\ub4dc\ub97c \uc2dc\uc791/\uacc4\uc18d\ud569\ub2c8\ub2e4. \uc790\ub3d9\uc73c\ub85c .start_chapter_NO \ub610\ub294 .start_chapter_title\ub85c \ubcc0\ud658\ub429\ub2c8\ub2e4. \ub2e4\uc6b4\ub85c\ub4dc\ub41c \uc7a5\uc758 \uacbd\uc6b0 .recheck\uc640 \uc77c\uce58\ud574\uc57c \ud569\ub2c8\ub2e4.",
