	"download_options.start_chapter_title": "\uc774 \uc7a5 \uc81c\ubaa9\ubd80\ud130 \ub2e4\uc6b4\ub85c\ub4dc\ub97c \uc2dc\uc791/\uacc4\uc18d\ud569\ub2c8\ub2e4.",
	"download_options.start_list_serial": "\ub2e4\uc6b4\ub85c\ub4dc\ub97c \uc2dc\uc791\ud560 \uc791\ud488\uc758 \uc77c\ub828\ubc88\ud638\ub97c \uc9c0\uc815\ud569\ub2c8\ub2e4. \uc774 \uc77c\ub828\ubc88\ud638 \uc774\uc804\uc758 \uc791\ud488\uc740 \uac74\ub108\ub701\ub2c8\ub2e4. \uc77c\ubc18\uc801\uc73c\ub85c \uba85\ub839\uc904 \uc124\uc815\uc5d0\uc11c\ub9cc \uc0ac\uc6a9\ub429\ub2c8\ub2e4. \uae30\ubcf8\uac12:1",
	"download_options.timeout": "\uc6f9\ubb38\uc11c \ub610\ub294 \uc774\ubbf8\uc9c0 \ub2e4\uc6b4\ub85c\ub4dc \uc2dc\uac04 \ucd08\uacfc \uae30\uac04(ms). \uc2dc\uac04 \ucd08\uacfc \uae30\uac04\uc774 \ub108\ubb34 \uc791\uc73c\uba74(\uc608: 10\ucd08) \ud070 \ud30c\uc77c \ub2e4\uc6b4\ub85c\ub4dc\uac00 \uc2e4\ud328\ud558\uae30 \uc27d\uc2b5\ub2c8\ub2e4.",
	"download_options.user_agent": "\ube0c\ub77c\uc6b0\uc800 \uc2dd\ubcc4\uc790\uc785\ub2c8\ub2e4. \uc2e4\ud589 \uc804\ud6c4\uc5d0 \ud56d\uc0c1 \uac19\uc740 \ube0c\ub77c\uc6b0\uc800 \uc778\uc2dd\uc744 \uc720\uc9c0\ud558\uba70, \ub2e4\uc6b4\ub85c\ub4dc\uc5d0 \uc601\ud5a5\uc744 \uc8fc\uc9c0 \uc54a\uc544\uc57c \ud569\ub2c8\ub2e4.",
	"download_options.vertical_writing": "\uc18c\uc124\uc744 \uac00\ub85c\uc4f0\uae30\uc5d0\uc11c \uc138\ub85c\uc4f0\uae30\ub85c \ubcc0\uacbd\ud569\ub2c8\ub2e4.",
