	"\u540c\u6642\u66f4\u6539\u5df2\u624b\u52d5\u8a2d\u5b9a\u4e0b\u8f09\u76ee\u9304\u7684\u7db2\u7ad9 %1\uff1a%2 \u2192 %3": "%1\uc758 \ub2e4\uc6b4\ub85c\ub4dc \uc6f9\uc0ac\uc774\ud2b8 \uc5c5\ub370\uc774\ud2b8 \ubc0f \uc124\uc815 \uc911: %2 \u2192 %3",
	"\u820a\u4e0b\u8f09\u76ee\u9304 \"%1\" \u70ba\u7a7a\u76ee\u9304\uff0c\u5c07\u4e4b\u79fb\u9664\u3002": "\uc774\uc804 \ub2e4\uc6b4\ub85c\ub4dc \ub514\ub809\ud130\ub9ac \"%1\"\uc774(\uac00) \ube48 \ub514\ub809\ud130\ub9ac\uc774\ubbc0\ub85c \uc81c\uac70\ub429\ub2c8\ub2e4.",
	"\u6a94\u6848\u63db\u884c%1\u548c\u7cfb\u7d71\u63db\u884c%2\u4e0d\u7b26\u3002": "\ud30c\uc77c \uc904\ubc14\uafc8 %1\uc774(\uac00) \uc2dc\uc2a4\ud15c \uc904\ubc14\uafc8 %2\uc640(\uacfc) \uc77c\uce58\ud558\uc9c0 \uc54a\uc2b5\ub2c8\ub2e4.",
	"\u958b\u555f\u6a94\u6848\u6642\u53ef\u80fd\u6703\u6709\u4e82\u78bc\u3002": "\ud30c\uc77c\uc744 \uc5f4 \ub54c \ubb38\uc790\uac00 \uae68\uc9c8 \uc218 \uc788\uc2b5\ub2c8\ub2e4.",
	"\u4e00\u9375\u4fee\u6b63\u6a94\u6848\u63db\u884c": "\ud30c\uc77c \uc904\ubc14\uafc8 \ud55c \ubc88 \ud074\ub9ad\uc73c\ub85c \uc218\uc815",
	"\u5df2\u4fee\u6539\u6a94\u6848\u63db\u884c\u3002\u60a8\u5fc5\u9808\u5132\u5b58\u6700\u611b\u4f5c\u54c1\u6e05\u55ae\u624d\u80fd\u751f\u6548\u3002": "\ud30c\uc77c \uc904\ubc14\uafc8\uc744 \uc218\uc815\ud588\uc2b5\ub2c8\ub2e4. \uc801\uc6a9\ud558\ub824\uba74 \uc990\uaca8\ucc3e\uae30 \uc791\ud488 \ubaa9\ub85d\uc744 \uc800\uc7a5\ud574\uc57c \ud569\ub2c8\ub2e4.",
	"\u8acb\u5728\u6bcf\u4e00\u884c\u9375\u5165\u4e00\u500b\u4f5c\u54c1\u540d\u7a31\u6216\ud83c\udd94\uff1a": "\ud55c \uc904\uc5d0 \ud558\ub098\uc758 \uc2dc\ub9ac\uc988 \uc81c\ubaa9 \ub610\ub294 \ud83c\udd94\ub97c \uc785\ub825",
