	"\u672c\u4f5c\u4f9d\u7ae0\u7bc0\u6a19\u984c\u4f86\u6c7a\u5b9a\u7ae0\u7bc0\u7de8\u865f\uff1b\u5efa\u8b70\u8a2d\u7f6e recheck=multi_parts_changed \u9078\u9805\u4f86\u907f\u514d\u591a\u6b21\u4e0b\u8f09\u6642\uff0c\u9047\u4e0a\u7f3a\u8a71\u7684\u60c5\u6cc1\u3002": "\uc774 \uc139\uc158\uc740 \ucc55\ud130 \uc81c\ubaa9\uc5d0 \ub530\ub77c \ucc55\ud130 \ubc88\ud638\ub97c \uacb0\uc815\ud569\ub2c8\ub2e4. \uc5ec\ub7ec \ubc88 \ub2e4\uc6b4\ub85c\ub4dc\ud560 \ub54c \ub204\ub77d\ub418\ub294 \uc0c1\ud669\uc744 \ud53c\ud558\ub824\uba74 recheck=multi_parts_changed \uc635\uc158\uc744 \uc124\uc815\ud558\ub294 \uac83\uc774 \uc88b\uc2b5\ub2c8\ub2e4.",
	"\u300a%1\u300b\u51fa\u73fe\u7ae0\u7bc0\u7de8\u865f\u5012\u7f6e\u7684\u60c5\u6cc1\uff1a%2": "\u00ab%1\u00bb\uc758 \uacbd\uc6b0 \ucc55\ud130 \ubc88\ud638\uac00 \uc5ed\uc21c\uc785\ub2c8\ub2e4: %2",
	"\u7121\u6cd5\u5f9e\u7ae0\u7bc0\u6a19\u984c\u300a%1\u300b\u5224\u65b7\u7ae0\u7bc0\u5e8f\u865f\u3002": "\uc81c\ubaa9\uc5d0\uc11c \ucc55\ud130 \ubc88\ud638\ub97c \ud655\uc778\ud560 \uc218 \uc5c6\uc2b5\ub2c8\ub2e4: \u00ab%1\u00bb.",
	"\u7121\u6cd5\u5f9e\u7ae0\u7bc0\u8cc7\u6599\u5224\u65b7\u7ae0\u7bc0\u5e8f\u865f\uff1a%1\u3002": "\ucc55\ud130 \ub370\uc774\ud130\uc5d0\uc11c \ucc55\ud130 \ubc88\ud638\ub97c \ud655\uc778\ud560 \uc218 \uc5c6\uc2b5\ub2c8\ub2e4: %1",
	"\u4f9d\u5e8f\u5c07\u7ae0\u7bc0\u5e8f\u865f\u8a2d\u5b9a\u70ba %1\u3002": "\ucc55\ud130 \uc21c\uc11c\uc5d0 \ub530\ub77c \ucc55\ud130 \ubc88\ud638\ub97c %1\ub85c \uc124\uc815\ud569\ub2c8\ub2e4.",
	"\u5de5\u5177\u6a94\u8a2d\u5b9a\u4e86 part_title %1\uff0c\u537b\u4f3c\u4e4e\u672a\u8a2d\u5b9a\u61c9\u8a2d\u5b9a\u7684 `work_data.chapter_list.part_NO`? (part_NO: %2)": "\ub3c4\uad6c \ud30c\uc77c\uc5d0\ub294 part_title %1\uc774(\uac00) \uc124\uc815\ub418\uc5b4 \uc788\uc9c0\ub9cc, `work_data.chapter_list.part_NO`? (part_NO: %2)\uc744(\ub97c) \uc124\uc815\ud574\uc57c \ud558\ub294 \uac83 \uac19\uc2b5\ub2c8\ub2e4.",
	"\u672c\u4f5c\u5b58\u6709\u4e0d\u540c\u7684 part\uff1b\u5efa\u8b70\u8a2d\u7f6e recheck=multi_parts_changed \u9078\u9805\u4f86\u907f\u514d\u591a\u6b21\u4e0b\u8f09\u6642\uff0c\u9047\u4e0a\u7f3a\u8a71\u7684\u60c5\u6cc1\u3002": "\uc774 \uc791\ud488\uc5d0\ub294 \ub2e4\ub978 \ud30c\ud2b8\uac00 \uc788\uc2b5\ub2c8\ub2e4. \uc5ec\ub7ec \ubc88 \ub2e4\uc6b4\ub85c\ub4dc\ud560 \ub54c \ub204\ub77d\ub418\ub294 \uc0c1\ud669\uc744 \ud53c\ud558\ub824\uba74 recheck=multi_parts_changed \uc635\uc158\uc744 \uc124\uc815\ud558\ub294 \uac83\uc774 \uc88b\uc2b5\ub2c8\ub2e4.",
	"Invalid chapter_data: %1": "\uc798\ubabb\ub41c chapter_data: %1",
	"\u7121\u6cd5\u53d6\u5f97 \u00a7%1 \u7684\u7db2\u5740\u3002": "\u00a7%1\uc758 \uc6f9 \uc8fc\uc18c\ub97c \ubc1b\uc744 \uc218 \uc5c6\uc2b5\ub2c8\ub2e4.",
	"Getting data of chapter %1, %2": "\ucc55\ud130 %1, %2\uc758 \ub370\uc774\ud130\ub97c \uac00\uc838\uc624\ub294 \uc911",
	"Getting data of chapter %1": "\ucc55\ud130 %1\uc758 \ub370\uc774\ud130\ub97c \uac00\uc838\uc624\ub294 \uc911",
	"\u5148\u5275\u5efa\u7ae0\u7bc0\u76ee\u9304\uff1a%1": "\ucc55\ud130 \ub514\ub809\ud130\ub9ac \uc0dd\uc131 \uc911: %1",
	"\u89e3\u958b\u5716\u7247\u58d3\u7e2e\u6a94\uff1a%1": "\uc774\ubbf8\uc9c0 \ud30c\uc77c \ucd94\ucd9c \uc911: %1",
	"\u8b80\u53d6\u5716\u7247\u58d3\u7e2e\u6a94\uff1a%1": "\uc774\ubbf8\uc9c0 \uc544\uce74\uc774\ube0c \uc77d\ub294 \uc911: %1",
	"\u522a\u9664\u7ae0\u7bc0\u5167\u5bb9\u9801\u9762\uff1a%1": "\ucc55\ud130\uc5d0\uc11c \uc774\ubbf8\uc9c0 \uc0ad\uc81c \uc911: %1",
	"%1 [%2] %3 {{PLURAL:%3|image|images}}.": "%1 [%2] %3\uac1c {{PLURAL:%3|\uc774\ubbf8\uc9c0}}.",
