	"%1\uff1a\u5df2\u6d3e\u767c\u5b8c\u5de5\u4f5c\uff0c\u958b\u59cb\u4e26\u884c\u4e0b\u8f09\u5404\u5716\u7247\u3002": "%1: \uc791\ud488\uc774 \ubc30\uc815\ub418\uc5c8\uc73c\uba70 \uc774\ubbf8\uc9c0\uac00 \ubcd1\ub82c\ub85c \ub2e4\uc6b4\ub85c\ub4dc\ub429\ub2c8\ub2e4.",
