	"\u4e0b\u8f7d\u7b2c %2 \u5f35{{PLURAL:%2|\u5716\u7247}}\u524d\u5148\u7b49\u5f85 %1\u3002": "%1 \ub3d9\uc548 \uae30\ub2e4\ub9b0 \ud6c4 %2\uac1c {{PLURAL:%2|\uc774\ubbf8\uc9c0}}\ub97c \ub2e4\uc6b4\ub85c\ub4dc\ud569\ub2c8\ub2e4.",
	"\u7121\u6cd5\u53d6\u5f97\u7b2c %1 \u7ae0\u7684\u5167\u5bb9\u3002": "\ucc55\ud130 %1\uc758 \ub370\uc774\ud130\ub97c \uac00\uc838\uc624\uc9c0 \ubabb\ud588\uc2b5\ub2c8\ub2e4",
	"\u8df3\u904e %1 \u00a7%2 \u4e26\u63a5\u8457\u4e0b\u8f09\u4e0b\u4e00\u7ae0\u3002": "%1 \u00a7%2\uc744(\ub97c) \uac74\ub108\ub6f0\uace0 \ub2e4\uc74c \ucc55\ud130\ub97c \uacc4\uc18d\ud569\ub2c8\ub2e4.",
	"MESSAGE_NEED_RE_DOWNLOAD": "\ub2e4\uc6b4\ub85c\ub4dc\uc5d0 \ubb38\uc81c\uac00 \ubc1c\uc0dd\ud588\uc2b5\ub2c8\ub2e4. \uc11c\ubc84\uac00 \uc77c\uc2dc\uc801\uc73c\ub85c \uc0ac\uc6a9\ud560 \uc218 \uc5c6\uac70\ub098 \ud30c\uc77c\uc774 \uc190\uc2e4\ub41c \uac83(404) \ub54c\ubb38\uc77c \uc218 \uc788\uc2b5\ub2c8\ub2e4. \uc624\ub958\uac00 \uc81c\uac70\ub418\uc5c8\uac70\ub098 \ub354 \uc774\uc0c1 \uacc4\uc18d\ub418\uc9c0 \uc54a\ub294\uc9c0 \ud655\uc778\ud55c \ub4a4 \ub2e4\uc2dc \uc2e4\ud589\ud558\uc5ec \ub2e4\uc6b4\ub85c\ub4dc\ub97c \uacc4\uc18d\ud558\uc138\uc694.",
	"Retry %1/%2": "%1/%2 \uc7ac\uc2dc\ub3c4",
	"\u56e0\u5feb\u53d6\u6a94\u6848\u58de\u4e86\uff08\u4f8b\u5982\u70ba\u7a7a\u6a94\u6848\uff09\uff0c\u5c07\u91cd\u65b0\u53d6\u5f97 chapter_URL\uff0c\u8a2d\u5b9a .reget_chapter\u3002": "\uce90\uc2dc \ud30c\uc77c\uc774 \uc190\uc0c1\ub418\uc5c8\uc73c\ubbc0\ub85c(\uc608: \ube48 \ud30c\uc77c) chapter_URL\uc744 \ub2e4\uc2dc \uac00\uc838\uc624\uace0 .reget_chapter\uac00 \uc124\uc815\ub429\ub2c8\ub2e4.",
	"\u7ae0\u7bc0\u7de8\u865f\u4f9d\u5e8f\u61c9\u70ba %1\uff0c\u4f46\u7121\u6cd5\u81ea\u7ae0\u7bc0\u5167\u5bb9\u53d6\u5f97\u7de8\u865f\u3002": "\ucc55\ud130 \ubc88\ud638\ub294 \uc21c\uc11c\uc0c1 %1\uc774\uc5b4\uc57c \ud558\uc9c0\ub9cc, \ucc55\ud130 \ub0b4\uc6a9\uc5d0\uc11c \ubc88\ud638\ub97c \uc5bb\uc744 \uc218 \uc5c6\uc2b5\ub2c8\ub2e4.",
	"\u7ae0\u7bc0\u7de8\u865f\u4e0d\u4e00\u81f4\uff1a\u4f9d\u5e8f\u61c9\u70ba %1\uff0c\u4f46\u5f9e\u5167\u5bb9\u64f7\u53d6\u51fa %2\u3002": "\ucc55\ud130 \ubc88\ud638\uac00 \uc77c\uce58\ud558\uc9c0 \uc54a\uc2b5\ub2c8\ub2e4. \uc21c\uc11c\uc0c1 %1\uc774\uc5b4\uc57c \ud558\uc9c0\ub9cc, \ub0b4\uc6a9\uc5d0\uc11c\ub294 %2\uc744(\ub97c) \uac00\uc838\uc654\uc2b5\ub2c8\ub2e4.",
	"\u7b49\u5f85 %2 \u4e4b\u5f8c\u518d\u91cd\u65b0\u53d6\u5f97\u7ae0\u7bc0\u5167\u5bb9\u9801\u9762\uff1a%1": "%2 \ub3d9\uc548 \uae30\ub2e4\ub9b0 \ud6c4 \ucc55\ud130 \ubcf8\ubb38\uc744 \ub2e4\uc2dc \uac00\uc838\uc635\ub2c8\ub2e4: %1",
	"\u91cd\u65b0\u53d6\u5f97\u7ae0\u7bc0\u5167\u5bb9\u9801\u9762\uff1a%1": "\ucc55\ud130 \ubcf8\ubb38\uc744 \ub2e4\uc2dc \uac00\uc838\uc624\ub294 \uc911: %1",
	"\u7b49\u5f85 %2 \u4e4b\u5f8c\u518d\u53d6\u5f97\u7ae0\u7bc0\u5167\u5bb9\u9801\u9762\uff1a%1": "%2 \ub3d9\uc548 \uae30\ub2e4\ub9b0 \ud6c4 \ucc55\ud130 \ubcf8\ubb38\uc744 \uac00\uc838\uc635\ub2c8\ub2e4: %1",
	"\u53d6\u5f97\u7ae0\u7bc0\u5167\u5bb9\u9801\u9762\uff1a%1": "\ucc55\ud130 \ubcf8\ubb38 \uac00\uc838\uc624\uae30: %1",
	"\u89e3\u6790\u51fa\u7a7a\u7684\u9801\u9762\u8cc7\u8a0a\uff01": "\ube48 \ud398\uc774\uc9c0 \uc815\ubcf4\uac00 \uad6c\ubb38 \ubd84\uc11d\ub418\uc5c8\uc2b5\ub2c8\ub2e4!",
	"\u89e3\u6790\u7ae0\u7bc0\u9801\u9762\u6642\u767c\u751f\u932f\u8aa4\uff0c\u4e2d\u65b7\u8df3\u51fa\uff1a%1": "\ucc55\ud130 \ud398\uc774\uc9c0\ub97c \uad6c\ubb38 \ubd84\uc11d\ud558\ub294 \ub3d9\uc548 \uc624\ub958\uac00 \ubc1c\uc0dd\ud558\uc5ec \ub2e4\uc74c \uc704\uce58\uc5d0\uc11c \uc911\ub2e8\ub418\uc5c8\uc2b5\ub2c8\ub2e4: %1",
	"\u672c\u7ae0\u70ba\u9700\u8981\u4ed8\u8cbb/\u88ab\u9396\u4f4f\u7684\u7ae0\u7bc0\u3002": "\uc774 \ucc55\ud130\ub294 \uacb0\uc81c/\uc7a0\uae08\uc774 \ud544\uc694\ud55c \ucc55\ud130\uc785\ub2c8\ub2e4.",
	"\u672c\u7ae0\u7bc0\u6c92\u6709\u7372\u53d6\u5230\u4efb\u4f55\u5716\u7247\uff01": "\uc774 \ucc55\ud130\uc5d0\uc11c \uc774\ubbf8\uc9c0\ub97c \uac00\uc838\uc624\uc9c0 \ubabb\ud588\uc2b5\ub2c8\ub2e4!",
	"\u6240\u767b\u8a18\u7684\u5716\u5f62\u6578\u91cf%1\u8207\u6709\u5716\u5f62\u5217\u8868\u9577\u5ea6%2\u4e0d\u540c\uff01": "\ub4f1\ub85d\ub41c \uc774\ubbf8\uc9c0 \uc218 %1\uc774(\uac00) \uc774\ubbf8\uc9c0 \ubaa9\ub85d \uae38\uc774 %2\uc640(\uacfc) \ub2e4\ub985\ub2c8\ub2e4!",
	"\u539f\u5148\u7684\u7ae0\u7bc0\u8cc7\u6599\u8a2d\u5b9a\u4e86\u5206\u90e8\u6a19\u984c\uff0c\u4f46 .parse_chapter_data() \u50b3\u56de\u7684\u7ae0\u7bc0\u8cc7\u6599\u7f3a\u5c11\u4e86\u5206\u90e8\u6a19\u984c\u3002\u6216\u8a31\u60a8\u53ef\u4ee5\u6cbf\u7528\u539f\u5148\u7684\u7ae0\u7bc0\u8cc7\u6599\u3002": "\uc6d0\ub798 \ucc55\ud130 \ub370\uc774\ud130\uc5d0\ub294 \uad6c\ubd84 \uc81c\ubaa9\uc774 \uc124\uc815\ub418\uc5b4 \uc788\uc9c0\ub9cc .parse_chapter_data()\uac00 \ubc18\ud658\ud55c \ucc55\ud130 \ub370\uc774\ud130\uc5d0\ub294 \uad6c\ubd84 \uc81c\ubaa9\uc774 \uc5c6\uc2b5\ub2c8\ub2e4. \uc6d0\ub798 \ucc55\ud130 \ub370\uc774\ud130\ub97c \uc0ac\uc6a9\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.",
