	"%1\uff1a%2\u7b46{{PLURAL:%2|\u5716\u7247}}\u4e0b\u8f09\u932f\u8aa4\u7d00\u9304": "%1: %2\uac1c {{PLURAL:%2|\uc774\ubbf8\uc9c0}} \ub2e4\uc6b4\ub85c\ub4dc \uc624\ub958\uac00 \uae30\ub85d\ub428",
	"\u5f9e\u5716\u7247\u58d3\u7e2e\u6a94\u522a\u9664%1\u5f35\u672c\u6b21\u4e0b\u8f09\u6210\u529f\u3001\u4e0a\u6b21\u4e0b\u8f09\u5931\u6557\u7684\u640d\u58de\u5716\u7247\uff1a%2": "\uc774\ubc88\uc5d0 \uc131\uacf5\uc801\uc73c\ub85c \ub2e4\uc6b4\ub85c\ub4dc\ud55c \uc774\ubbf8\uc9c0 \uc555\ucd95 \ud30c\uc77c\uc5d0\uc11c \uc190\uc0c1\ub41c \uc774\ubbf8\uc9c0 %1\uac1c \uc81c\uac70: %2",
	"\u66f4\u65b0\u5716\u7247\u58d3\u7e2e\u6a94\uff1a%1": "\uc774\ubbf8\uc9c0 \uc544\uce74\uc774\ube0c \uc5c5\ub370\uc774\ud2b8: %1",
	"\u5275\u5efa\u5716\u7247\u58d3\u7e2e\u6a94\uff1a%1": "\uc774\ubbf8\uc9c0 \uc544\uce74\uc774\ube0c \uc0dd\uc131: %1",
	"%2: jump to chapter %1": "%2: \ucc55\ud130 %1\ub85c \uc774\ub3d9",
	"\u82e5\u6b32\u52d5\u614b\u589e\u52a0\u7ae0\u7bc0\uff0c\u5fc5\u9808\u624b\u52d5\u589e\u52a0\u7ae0\u7bc0\u6578\u91cf: work_data.chapter_count++\uff01": "\ucc55\ud130\ub97c \ub3d9\uc801\uc73c\ub85c \ucd94\uac00\ud558\ub824\uba74 \ucc55\ud130 \uc218\ub97c \uc218\ub3d9\uc73c\ub85c \ub298\ub824\uc57c \ud569\ub2c8\ub2e4: work_data.chapter_count++!",
	"\uff08\u672c\u6b21\u4e0b\u8f09\u5171\u8655\u7406 %1\u500b{{PLURAL:%1|\u5b57}}\uff09": "{\uc774 \ub2e4\uc6b4\uc740 \ucd1d %1 \ucc98\ub9ac\ud588\uc2b5\ub2c8\ub2e4 {{PLURAL:1|word|words}})",
