	"%1\uff1a\u672c\u6b21\u4e0b\u8f09\u4f5c\u696d\uff0c\u672c\u4f5c\u54c1\u5171 %2\u5f35{{PLURAL:%2|\u5716\u7247}}\u4e0b\u8f09\u932f\u8aa4\u3002": "%1: \uc774\ubbf8\uc9c0\ub97c \ub2e4\uc6b4\ub85c\ub4dc\ud560 \ub54c {{PLURAL:%2|%2\uac1c\uc758 \uc624\ub958\uac00 \uc788\uc2b5\ub2c8\ub2e4}}.",
