	"\u5c07\u8986\u5beb\u7e41\u7c21\u4e2d\u6587\u8f49\u63db\u5feb\u53d6\u76ee\u9304 [%1] \u4e2d\u7684\u6a94\u6848\u3002": "\ubc88\uccb4\uc790 \ubc0f \uac04\uccb4\uc790 \uc911\uad6d\uc5b4 \ubcc0\ud658\uc744 \uc704\ud574 \uce90\uc2dc \ub514\ub809\ud130\ub9ac [%1]\uc758 \ud30c\uc77c\uc744 \ub36e\uc5b4\uc501\ub2c8\ub2e4.",
