	"\u5f37\u5236\u5c07\u975e\u5716\u7247\u6a94\u5132\u5b58\u70ba\u5716\u7247\u3002": "\uc774\ubbf8\uc9c0\uac00 \uc544\ub2cc \ud30c\uc77c\uc744 \uac15\uc81c\ub85c \uc774\ubbf8\uc9c0\ub85c \uc800\uc7a5\ud569\ub2c8\ub2e4.",
