	"\u58d3\u7e2e\u6a94\u5167\u7684\u5716\u7247\u54c1\u8cea\u512a\u65bc\u76ee\u9304\u4e2d\uff0c\u4f46\u4e0b\u8f09\u5b8c\u5f8c\u53ef\u80fd\u5728\u58d3\u7e2e\u6642\u88ab\u8986\u84cb\uff1a%1": "\uc544\uce74\uc774\ube0c\uc758 \uc774\ubbf8\uc9c0 \ud488\uc9c8\uc774 \ub514\ub809\ud130\ub9ac\uc758 \uc774\ubbf8\uc9c0\ubcf4\ub2e4 \uc88b\uc9c0\ub9cc, \ub2e4\uc6b4\ub85c\ub4dc \ud6c4 \ub36e\uc5b4\uc368\uc9d1\ub2c8\ub2e4: %1",
	"\u58d3\u7e2e\u6a94\u5167\u7684\u5716\u7247\u54c1\u8cea\u512a\u65bc\u76ee\u9304\u4e2d\uff1a%1": "\uc544\uce74\uc774\ube0c\uc758 \uc774\ubbf8\uc9c0 \ud488\uc9c8\uc774 \ub514\ub809\ud130\ub9ac\uc758 \uc774\ubbf8\uc9c0\ubcf4\ub2e4 \uc88b\uc2b5\ub2c8\ub2e4: %1",
	"\u4fdd\u5b58\u5716\u7247\u6578\u64da\u5230\u786c\u789f\u4e0a\uff1a%1": "\uc774\ubbf8\uc9c0 \ub370\uc774\ud130\ub97c \ud558\ub4dc \ub4dc\ub77c\uc774\ube0c\uc5d0 \uc800\uc7a5: %1",
	"\u7121\u6cd5\u5beb\u5165\u5716\u7247\u6a94\u6848 [%1]\u3002": "[%1] \uc774\ubbf8\uc9c0 \ud30c\uc77c\uc744 \uc4f8 \uc218 \uc5c6\uc2b5\ub2c8\ub2e4.",
	"\u53ef\u80fd\u56e0\u70ba\u4f5c\u54c1\u4e0b\u8f09\u76ee\u9304\u6539\u8b8a\u4e86\uff0c\u800c\u5feb\u53d6\u8cc7\u6599\u6307\u5411\u4e0d\u5b58\u5728\u7684\u820a\u4f4d\u7f6e\u3002": "\uc791\ud488\uc758 \ub2e4\uc6b4\ub85c\ub4dc \ub514\ub809\ud130\ub9ac\uac00 \ubcc0\uacbd\ub418\uc5b4 \uce90\uc2dc \ub370\uc774\ud130\uac00 \uc874\uc7ac\ud558\uc9c0 \uc54a\ub294 \uc774\uc804 \uc704\uce58\ub97c \uac00\ub9ac\ud0a4\uace0 \uc788\uae30 \ub54c\ubb38\uc77c \uc218 \uc788\uc2b5\ub2c8\ub2e4.",
	"\u53ef\u80fd\u56e0\u70ba\u4f5c\u54c1\u8cc7\u8a0a\u5feb\u53d6\u8207\u7576\u524d\u7db2\u7ad9\u4e0a\u4e4b\u4f5c\u54c1\u7ae0\u7bc0\u7d50\u69cb\u4e0d\u540c\u3002": "\uc791\ud488 \uc815\ubcf4 \uce90\uc2dc\uac00 \ud604\uc7ac \uc6f9\uc0ac\uc774\ud2b8\uc758 \uc791\ud488 \ucc55\ud130 \uad6c\uc870\uc640 \ub2e4\ub974\uae30 \ub54c\ubb38\uc77c \uc218 \uc788\uc2b5\ub2c8\ub2e4.",
	"\u82e5\u60a8\u4e4b\u524d\u66fe\u7d93\u4e0b\u8f09\u904e\u672c\u4f5c\u54c1\u7684\u8a71\uff0c\u8acb\u5c01\u5b58\u539f\u6709\u4f5c\u54c1\u76ee\u9304\uff0c\u6216\u5c07\u4f5c\u54c1\u8cc7\u8a0a\u5feb\u53d6\u6a94\uff08\u4f5c\u54c1\u76ee\u9304\u4e0b\u7684 \u4f5c\u54c1id.json\uff09\u6539\u540d\u4e4b\u5f8c\u5617\u8a66\u5168\u65b0\u4e0b\u8f09\u3002": "\uc774\uc804\uc5d0 \uc774 \uc791\ud488\uc744 \ub2e4\uc6b4\ub85c\ub4dc\ud55c \uc801\uc774 \uc788\ub2e4\uba74 \uc6d0\ub798 \uc791\ud488 \uce74\ud0c8\ub85c\uadf8\ub97c \uc800\uc7a5\ud558\uac70\ub098, \uc791\ud488 \uce90\uc2dc \ud30c\uc77c(\uc791\ud488 \ub514\ub809\ud130\ub9ac \uc544\ub798\uc758 \uc791\ud488 id.json)\uc758 \uc774\ub984\uc744 \ubc14\uafbc \ub4a4 \uc0c8\ub85c \ub2e4\uc6b4\ub85c\ub4dc\ud574 \ubcf4\uc138\uc694.",
	"\u5b58\u5728\u8f03\u5927\u7684\u820a\u6a94 (%2)\uff0c\u5c07\u4e0d\u8986\u84cb\uff1a%1": "\ub36e\uc5b4\uc4f0\uc9c0 \uc54a\uc744 \ud070 \uc774\uc804 \ud30c\uc77c(%2)\uc774 \uc788\uc2b5\ub2c8\ub2e4: %1",
