	"\u7121\u6cd5\u53d6\u5f97\u5716\u7247\u3002": "\uc774\ubbf8\uc9c0 \uac00\uc838\uc624\uae30\ub97c \uc2e4\ud328\ud588\uc2b5\ub2c8\ub2e4. ",
